1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { items: Item[] };
14	type Scenario = { steps: Step[] };
15	
16	export function processScenario(scenario: unknown): unknown {
17	  const { steps } = scenario as Scenario;
18	  const items = steps[0].items;
19	  const runeCount = items.filter((item) => item.type === "rune").length;
20	  const isRuneBlock = runeCount === 3 && items.length === 3;
21	  const basePremium = isRuneBlock
22	    ? 60
23	    : items.reduce(
24	        (sum, item) => sum + (BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0),
25	        0,
26	      );
27	  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
28	}
